mapper.sql:
WHERE 1 = 1
AND b.use_yn = 'Y'

    AND IFNULL(b.like_count, 0) >= #{minLikeCount}


    AND b.category_code = #{categoryCode}


    AND b.title LIKE CONCAT('%', #{title}, '%')


    AND b.writer_name LIKE CONCAT('%', #{writerName}, '%')


    AND (b.title LIKE CONCAT('%', #{keyword}, '%') OR b.content LIKE CONCAT('%', #{keyword}, '%'))


    AND b.show_yn = #{showYn}


    AND b.highlight_yn = #{highlightYn}

WHERE 1 = 1
AND b.use_yn = 'Y'
AND cg.code_group_id = 'A0007'

    AND IFNULL(b.like_count, 0) >= #{minLikeCount}


    AND b.category_code = #{categoryCode}


    AND b.title LIKE CONCAT('%', #{title}, '%')


    AND b.writer_name LIKE CONCAT('%', #{writerName}, '%')


    AND (b.title LIKE CONCAT('%', #{keyword}, '%') OR b.content LIKE CONCAT('%', #{keyword}, '%'))


    AND b.show_yn = #{showYn}


    AND b.highlight_yn = #{highlightYn}
